select a.accentity, b.nori_amount as oriSum,d.bill_date as vouchdate,a.code,b.dept_id as dept,b.project_id as project,b.id,b.header_id as mainid
from stwb_apply_detail b
INNER JOIN stwb_settleapply a on a.id = b.header_id
INNER JOIN stwb_settleapply_fund_assistant d on a.id = d.id
INNER JOIN stwb_settleapplydetail_fund_assistant c on c.id = b.id
where
a.ytenant_id = #{ytenantid}
and b.ytenant_id = #{ytenantid}
and c.ytenant_id = #{ytenantid}
and d.ytenant_id = #{ytenantid}

    and c.description like CONCAT('%', #{remark}, '%')


    and c.description = #{remark}


    and b.nori_amount = #{money}


    and b.opp_bank_acct_no = #{othBankNum}



    and b.opp_bank_acct_name = #{to_acct_name}



    and (b.opp_bank_acct_no is null or b.opp_bank_acct_name  = #{to_acct_name} )



    and ( b.opp_bank_acct_name is null or b.opp_bank_acct_no = #{othBankNum})



    and b.curr_bank_acct_id = #{ourBankNum}

and d.bill_date BETWEEN #{startTime} and #{endTime}
and a.verifystate = '0'
and c.association_status = 0
and a.ebiz_obj_type = 'cmp.fundpayment.FundPayment'

