select accentity, oriSum, vouchdate, code, project, id
from cm_transfer_account
where
tenant_id = #{tenantid}

    and description like CONCAT('%', #{remark}, '%')


    and description = #{remark}


    and oriSum = #{money}



    and recbankaccount = #{othBankNum_id}



    and paybankaccount = #{ourBankNum}

and vouchdate BETWEEN #{startTime} and #{endTime}
and verifystate != 3
and associationStatusPay = 0

